function fb(a, b) { if (a) { return a; } return b; }
var now = new Date();
var lookAhead = fb($.input.lookAheadDays, 5);
var end = new Date(now);
end.setDate(end.getDate() + lookAhead);
return {
  timeMin: now.toISOString(),
  timeMax: end.toISOString(),
  today: now.toISOString().split('T')[0],
  endDate: end.toISOString().split('T')[0],
  workStart: fb($.input.workingHoursStart, 9),
  workEnd: fb($.input.workingHoursEnd, 17)
};

function fb(a, b) { if (a) { return a; } return b; }
var events = fb(fb($.steps.listEvents.response, {}).items, []);
var dateRange = $.steps.getDateRange.output;
var workStart = dateRange.workStart;
var workEnd = dateRange.workEnd;

var busySlots = '';
events.forEach(function(e, i) {
  var start = e.start ? (fb(fb(e.start.dateTime, e.start.date), '')) : '';
  var end = e.end ? (fb(fb(e.end.dateTime, e.end.date), '')) : '';
  busySlots += '- ' + (fb(e.summary, 'Busy')) + ': ' + start + ' to ' + end + '\n';
});

var scheduleInfo = 'CALENDAR AVAILABILITY CHECK\n';
scheduleInfo += 'Period: ' + dateRange.today + ' to ' + dateRange.endDate + '\n';
scheduleInfo += 'Working hours: ' + workStart + ':00 - ' + workEnd + ':00\n';
scheduleInfo += 'Total existing events: ' + events.length + '\n\n';
scheduleInfo += 'BUSY TIMES:\n' + busySlots;

return { scheduleInfo: scheduleInfo, eventCount: events.length };

function fb(a, b) { if (a) { return a; } return b; }
var data = $.steps.analyzeAvailability.output;
var request = fb($.input.meetingRequest, '');

var prompt = 'You are a smart scheduling assistant. Based on the calendar availability below, suggest optimal meeting times for the requested meeting.\n\n';
prompt += 'MEETING REQUEST: ' + request + '\n\n';
prompt += data.scheduleInfo + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Suggest 3 specific time slots that avoid conflicts\n';
prompt += '- Prefer morning slots for important meetings\n';
prompt += '- Avoid back-to-back meetings (leave 15min buffer)\n';
prompt += '- Consider meeting duration from the request\n';
prompt += '- Note any days that are particularly busy or free\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "interpretation": "what meeting is being requested",\n';
prompt += '  "suggestedDuration": "recommended duration",\n';
prompt += '  "slots": [\n';
prompt += '    { "rank": 1, "date": "YYYY-MM-DD", "startTime": "HH:MM", "endTime": "HH:MM", "reason": "why this slot is good" }\n';
prompt += '  ],\n';
prompt += '  "busyDays": ["days that are heavily booked"],\n';
prompt += '  "freeDays": ["days with most availability"],\n';
prompt += '  "schedulingTips": "any relevant advice",\n';
prompt += '  "conflicts": ["any potential issues to watch for"]\n';
prompt += '}';

return { prompt: prompt };

function fb(a, b) { if (a) { return a; } return b; }
var raw = fb($.steps.aiAnalysis.output, '');
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { interpretation: raw, slots: [], schedulingTips: '' }; }

function fb(a, b) { if (a) { return a; } return b; }
var ai = $.steps.parseResponse.output;
var request = $.input.meetingRequest;

var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':calendar: Scheduling Assistant', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Request:* ' + request + '\n*Duration:* ' + (fb(ai.suggestedDuration, 'TBD')) } });
blocks.push({ type: 'divider' });

var slots = fb(ai.slots, []);
if (slots.length > 0) {
  var slotsText = '*:star: Recommended Time Slots*\n\n';
  slots.forEach(function(slot) {
    var medal = ':first_place_medal:';
    if (slot.rank === 2) medal = ':second_place_medal:';
    if (slot.rank === 3) medal = ':third_place_medal:';
    slotsText += medal + ' *' + slot.date + '* ' + slot.startTime + ' - ' + slot.endTime + '\n';
    slotsText += '   _' + (fb(slot.reason, '')) + '_\n\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: slotsText } });
}

var busyDays = fb(ai.busyDays, []);
var freeDays = fb(ai.freeDays, []);
if (busyDays.length > 0) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':no_entry: *Busy:* ' + busyDays.join(', ') + '  |  :white_check_mark: *Open:* ' + freeDays.join(', ') }] });
}

var conflicts = fb(ai.conflicts, []);
if (conflicts.length > 0) {
  var conflictText = ':warning: *Watch out:*\n';
  conflicts.forEach(function(c) { conflictText += '- ' + c + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: conflictText } });
}

if (ai.schedulingTips) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':bulb: ' + ai.schedulingTips }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Google Calendar + Claude AI + One CLI' }] });

var fallback = 'Scheduling: ' + slots.length + ' time slots suggested for ' + request;
return { blocks: blocks, fallback: fallback };
